   765→/**
   766→ * POST /api/payroll/pay-periods/generate
   767→ * Auto-generate pay periods for a country
   768→ */
   769→router.post('/pay-periods/generate', authMiddleware, requireRole('employer', 'recruiter', 'hiring_manager', 'admin'), async (req, res) => {
   770→  try {
   771→    const companyId = getCompanyId(req.user);
   772→    if (!companyId) return res.status(400).json({ error: 'No company' });
   773→
   774→    const { country_code, months } = req.body;
   775→    const cc = country_code || 'US';
   776→    const monthCount = months || 3;
   777→    const freq = PAY_FREQ_DEFAULTS[cc] || 'bi-weekly';
   778→    const periods = [];
   779→
   780→    const now = new Date();
   781→    let current = new Date(now.getFullYear(), now.getMonth(), 1);
   782→
   783→    if (freq === 'monthly') {
   784→      // Monthly: 1st to last day of month, paid on last day
   785→      for (let i = 0; i < monthCount; i++) {
   786→        const start = new Date(current);
   787→        const end = new Date(current.getFullYear(), current.getMonth() + 1, 0);
   788→        const payDate = new Date(end);
   789→        periods.push({ start, end, payDate });
   790→        current = new Date(current.getFullYear(), current.getMonth() + 1, 1);
   791→      }
   792→    } else {
   793→      // Bi-weekly: 14-day periods
   794→      // Find the most recent Monday
   795→      const day = current.getDay();
   796→      const monday = new Date(current);
   797→      monday.setDate(monday.getDate() - (day === 0 ? 6 : day - 1));
   798→
   799→      for (let i = 0; i < monthCount * 2; i++) {
   800→        const start = new Date(monday);
   801→        start.setDate(start.getDate() + i * 14);
   802→        const end = new Date(start);
   803→        end.setDate(end.getDate() + 13);
   804→        const payDate = new Date(end);
   805→        payDate.setDate(payDate.getDate() + 5); // Pay 5 days after period end
   806→        periods.push({ start, end, payDate });
   807→      }
   808→    }
   809→
   810→    // Insert periods
   811→    for (const p of periods) {
   812→      await pool.query(`
   813→        INSERT INTO pay_periods (company_id, country_code, period_type, period_start, period_end, pay_date)
   814→        VALUES ($1, $2, $3, $4, $5, $6)
   815→        ON CONFLICT DO NOTHING
   816→      `, [companyId, cc, freq, p.start, p.end, p.payDate]);
   817→    }
   818→
   819→    res.json({ message: `Generated ${periods.length} pay periods`, count: periods.length });
   820→  } catch (err) {
   821→    console.error('Generate pay periods error:', err);
   822→    res.status(500).json({ error: 'Failed to generate pay periods' });
   823→  }
   824→});
